# backend/services/billing/invoice_processor.py

from decimal import Decimal
from typing import Iterable

from services.billing.models import LineItem, Invoice


def _compute_line_subtotal(item: LineItem) -> Decimal:
    return item.unit_price * item.quantity


def _apply_line_discount(item: LineItem, subtotal: Decimal) -> Decimal:
    if item.discount_pct is None:
        return subtotal
    return subtotal * (Decimal(1) - item.discount_pct / Decimal(100))


def compute_invoice_total(items: Iterable[LineItem]) -> Decimal:
    total = Decimal(0)
    for item in items:
        sub = _compute_line_subtotal(item)
        total += _apply_line_discount(item, sub)
    return total


def finalize_invoice(invoice: Invoice) -> Invoice:
    invoice.total = compute_invoice_total(invoice.items)
    invoice.status = 'finalized'
    return invoice


def rollback_to_draft(invoice: Invoice) -> Invoice:
    invoice.status = 'draft'
    invoice.total = Decimal(0)
    return invoice
